INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Merchant of Record tax handling$q$, $q$Lemon Squeezy is the legal seller on every transaction, calculating, collecting and remitting sales tax and VAT worldwide so sellers do not need to register in each jurisdiction.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Hosted checkout and storefronts$q$, $q$Embeddable checkout overlays, payment links and hosted product pages for selling software and digital goods.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Subscription billing and dunning$q$, $q$Recurring billing with automated retry logic and dunning emails to recover failed payments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$License key management$q$, $q$Automatic generation and validation of software license keys tied to purchases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Built-in affiliate program$q$, $q$Sellers can run an affiliate program directly inside Lemon Squeezy without a third-party tool.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Fraud and chargeback protection$q$, $q$As merchant of record, Lemon Squeezy absorbs fraud screening and chargeback liability.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Multi-currency global payments$q$, $q$Accepts cards and PayPal across multiple currencies for a global customer base.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Developer API and webhooks$q$, $q$REST API and webhooks for integrating checkout, licensing and subscription events into a product.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$No monthly fee, only pay a percentage on actual sales$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Removes the burden of registering for sales tax and VAT in multiple countries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Fast setup, popular with solo developers and small SaaS teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Now backed by Stripe's payments infrastructure post-acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Built-in licensing and affiliate tools reduce the need for extra integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$The flat $0.50 per-transaction fee hurts margins on low-priced products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Less checkout customization than building directly on Stripe$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Long-term roadmap is uncertain as Stripe develops its own Stripe Managed Payments product$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Extra surcharges stack for PayPal, international sales, subscriptions and affiliates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Payout schedules and reserve holds can feel restrictive for new sellers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$What is Lemon Squeezy$q$, $q$Lemon Squeezy is a merchant-of-record platform that handles payments, subscription billing, licensing and global tax compliance for software and digital product sellers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Is Lemon Squeezy owned by Stripe$q$, $q$Yes. Stripe acquired Lemon Squeezy in July 2024 for an undisclosed amount, and it now operates as part of Stripe while continuing to run as its own product.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$How much does Lemon Squeezy cost$q$, $q$The base fee is 5% plus $0.50 per transaction with no monthly charge, plus small surcharges for PayPal, international sales, subscriptions, cart recovery and affiliate-referred sales.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Does Lemon Squeezy handle sales tax and VAT$q$, $q$Yes, because it acts as the merchant of record, Lemon Squeezy is responsible for calculating, collecting and remitting sales tax and VAT on behalf of sellers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$What happens to Lemon Squeezy now that Stripe has its own Managed Payments product$q$, $q$Lemon Squeezy continues to operate for existing and new customers, and Stripe has outlined a migration path to its native Stripe Managed Payments merchant-of-record feature over time.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Who is Lemon Squeezy best suited for$q$, $q$Indie developers, solo SaaS founders and small software or digital-product companies that want to avoid building their own global tax and billing infrastructure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Selling a subscription SaaS product globally$q$, $q$A small SaaS team uses Lemon Squeezy to bill customers in multiple countries without registering for VAT and sales tax in each region themselves.$q$, $q$Indie SaaS founders and small software teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Selling one-time digital downloads$q$, $q$A creator selling templates, ebooks or plugins uses Lemon Squeezy's hosted checkout and licensing to deliver and protect digital products.$q$, $q$Digital product creators and indie developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Running an affiliate-driven launch$q$, $q$A software company uses Lemon Squeezy's built-in affiliate manager to recruit promoters and track referred sales at launch without extra tooling.$q$, $q$Small software companies running product launches$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Standard$q$, $q$5% + $0.50 per transaction$q$, $q$Per transaction, no monthly fee$q$, NULL, $q$["Merchant of record tax handling","Hosted checkout and storefronts","Subscription billing","License key management","Built-in affiliate program"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$Custom$q$, $q$Custom pricing$q$, $q$Negotiated$q$, NULL, $q$["Volume discounts for high-transaction businesses","Better rates for sub-$10 priced products","Dedicated support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lemon Squeezy is a merchant-of-record platform purpose-built for software and digital product sellers. Rather than acting as a simple payment processor, Lemon Squeezy becomes the legal seller on every transaction, taking on the burden of calculating and remitting sales tax and VAT in every jurisdiction where a customer buys, which is the platform's core value proposition for small teams selling globally.$q$, $q$Founded around 2021 by CEO JR Farr, the company stayed small and largely self-funded, reportedly with about 13 employees, before being acquired by Stripe in July 2024 for an undisclosed amount. It continues to operate as a distinct product while Stripe builds its own native merchant-of-record feature, Stripe Managed Payments, with a migration path planned for existing Lemon Squeezy merchants.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform centers on a hosted checkout and storefront that sellers can embed as an overlay or link on their own site, supporting one-time purchases, subscriptions, license key delivery for software, and multi-currency payments including card and PayPal. Because Lemon Squeezy is the merchant of record, tax compliance, fraud screening and chargeback liability sit with Lemon Squeezy rather than the seller.$q$, $q$Beyond checkout, Lemon Squeezy includes subscription dunning and recovery workflows, an abandoned cart recovery feature, and a built-in affiliate program manager, letting sellers recruit and pay promoters without integrating a separate affiliate platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('38ebcc23-ac70-4e3b-9657-c3d8f9ce03db', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lemon Squeezy charges a single usage-based fee of 5% plus $0.50 per transaction with no monthly subscription cost, so businesses only pay when they make a sale. Additional surcharges apply for specific transaction types: +1.5% for international transactions, +1.5% for PayPal, +0.5% for recurring subscription charges, +5% for converted abandoned-cart recovery emails, and +3% for affiliate-referred sales.$q$, $q$High-volume sellers or those pricing products under roughly $10 can request custom pricing, since the flat $0.50 fee eats disproportionately into low-ticket sales.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Text-to-image and image-to-image generation$q$, $q$Generate images from text prompts or transform existing images using Leonardo's fine-tuned diffusion models.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$AI Canvas editing$q$, $q$Real-time inpainting and outpainting canvas for editing and extending generated images.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Consistent Character Engine$q$, $q$Maintains a consistent character appearance across multiple image generations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Custom LoRA model training$q$, $q$Train custom models on your own reference images for on-brand or on-style output.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$3D texture generation$q$, $q$Generates game-ready textures, originally built for video game asset production.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Image upscaling$q$, $q$AI-powered upscaling for higher-resolution output from generated images.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Developer API$q$, $q$API access on higher tiers for embedding Leonardo's models into apps and pipelines.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Real-time generation mode$q$, $q$Fast iteration mode for rapidly exploring prompt and style variations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Strong roots in game-asset generation give it strengths competitors lack, like 3D textures$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Consistent Character Engine and LoRA training support brand- and character-consistent output$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Generous free tier compared to some competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Now backed by Canva's resources and distribution while still operating as a specialist tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Real-time Canvas makes iterative editing faster than prompt-only workflows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Token consumption can be confusing and varies by model and settings$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$API access is gated behind the $30/month Artisan tier or higher$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Free tier tokens can run out quickly with a single day of heavy use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Output quality for certain styles still trails Midjourney for some use cases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Acquisition by Canva raises long-term questions about product independence$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$What is Leonardo AI$q$, $q$Leonardo AI is an AI image and visual asset generation platform, originally built for video game art, now used broadly for marketing, design and creative image generation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Is Leonardo AI owned by Canva$q$, $q$Yes, Canva acquired Leonardo AI in July 2024, though Leonardo continues to operate as its own product and brand.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$How much does Leonardo AI cost$q$, $q$Leonardo AI has a free tier with 150 tokens per day, and paid plans starting at $12/month (Apprentice) up to $60/month (Maestro), each with more tokens and features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Does Leonardo AI have an API$q$, $q$Yes, API access is available on the Artisan ($30/month) and Maestro ($60/month) plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$What was Leonardo AI originally built for$q$, $q$It was originally built to help video game developers generate art assets like textures and character concepts faster and more cheaply.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$How many users does Leonardo AI have$q$, $q$Leonardo AI passed 19 million registered users within roughly two years of launching.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Generating game art assets$q$, $q$Indie game studios use Leonardo to generate concept art, character designs and 3D textures faster than manual production.$q$, $q$Video game developers and studios$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$On-brand marketing visuals$q$, $q$Marketing teams use custom LoRA models and the Consistent Character Engine to generate on-brand imagery at scale.$q$, $q$Marketing and content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Creative exploration and hobbyist art$q$, $q$Individual creators use the free and Apprentice tiers to experiment with AI-generated art and illustration.$q$, $q$Hobbyist artists and individual creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["150 tokens per day","Community generations only","No API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Apprentice$q$, $q$$12/month$q$, $q$Monthly (annual saves ~30%)$q$, NULL, $q$["8,500 tokens per month","Private generations","Consistent Character Engine","Custom LoRA training"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Artisan$q$, $q$$30/month$q$, $q$Monthly (annual saves ~30%)$q$, NULL, $q$["25,000 tokens per month","Full Canvas editing suite","3D texture generation","API access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$Maestro$q$, $q$$60/month$q$, $q$Monthly (annual saves ~30%)$q$, NULL, $q$["60,000 tokens per month","Priority generation","Custom model training at scale","Best for heavy commercial use"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Leonardo AI began in Sydney in December 2022 as a tool for generating video game art assets faster and more cheaply than traditional production pipelines, founded by JJ Fiasson, Chris Gillis, Jachin Bhasme and co-founders. It grew rapidly into a broader AI image generation platform used by marketers, designers and hobbyists, reaching over 19 million registered users within about two years.$q$, $q$In July 2024, Canva announced its acquisition of Leonardo AI, reportedly valued above $320 million, bringing all roughly 120 Leonardo employees into Canva while allowing Leonardo to continue operating as a distinct product and brand focused on advanced, fine-tunable image generation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Leonardo's platform includes text-to-image and image-to-image generation using its own fine-tuned models, a real-time Canvas for inpainting and outpainting, custom LoRA model training on user-supplied reference images, and a Consistent Character Engine for keeping a character's look stable across many generations.$q$, $q$Additional tools include 3D texture generation aimed at game developers, image upscaling, and an API for embedding Leonardo's models into external applications and creative pipelines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('680a2bd4-9753-4f67-b86c-2cfe5c3b463e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Leonardo AI uses a token-based freemium model. The Free tier includes 150 tokens per day but excludes private generations and API access. Paid tiers are Apprentice at $12/month (8,500 tokens), Artisan at $30/month (25,000 tokens, unlocks Canvas and API access), and Maestro at $60/month (60,000 tokens, priority generation for heavy commercial use).$q$, $q$Annual billing reduces the cost of any paid plan by roughly 30% compared to paying monthly.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Unified contact and company management$q$, $q$Centralized records for contacts and companies with unlimited storage of contact data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Custom pipelines$q$, $q$Track deals, leads or projects through customizable pipeline stages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Task and calendar management$q$, $q$Task reminders and calendar syncing with Google Calendar and Outlook.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Custom fields and permissions$q$, $q$Tailor data fields and control what team members can see and edit.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Lead tracking$q$, $q$Track leads from first contact through the sales process.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Email logging$q$, $q$Log emails to contact records via BCC or email client add-ons.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Mobile access$q$, $q$Full CRM access from mobile browsers for on-the-go updates.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Simple reporting$q$, $q$Basic reporting on pipeline and team activity without complex configuration.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Single, transparent flat price with no feature gating or upsells$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$30-day free trial with full feature access and no credit card required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Simple enough for non-technical small business owners to set up themselves$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Highly rated, responsive customer support$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Bootstrapped and profitable, reducing risk of sudden pricing or ownership changes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Lacks advanced automation and AI features found in larger CRMs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Limited native integrations compared to Salesforce or HubSpot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Reporting is basic relative to enterprise-grade CRM analytics$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Not designed for large, complex enterprise sales organizations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$No free tier, only a time-limited trial$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$How much does Less Annoying CRM cost$q$, $q$It costs a flat $15 per user per month with no tiers or contracts, and every feature is included at that single price.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Does Less Annoying CRM have a free trial$q$, $q$Yes, a 30-day free trial with full access to all features and no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Who is Less Annoying CRM built for$q$, $q$Small businesses and independent professionals such as insurance agents, real estate agents and consultants who want simple contact and pipeline tracking.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Is Less Annoying CRM a venture-backed company$q$, $q$No, it has remained privately owned, bootstrapped and profitable since being founded in 2009.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Does Less Annoying CRM integrate with other tools$q$, $q$It offers a REST API, Zapier connectivity, and integrations with Google Calendar, Outlook and email logging, though its integration ecosystem is smaller than larger CRMs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Is Less Annoying CRM good for large enterprise teams$q$, $q$It is intentionally built for small businesses and is not designed to handle the complexity of large enterprise sales organizations.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Small sales team tracking leads and deals$q$, $q$A small business uses custom pipelines to track leads from first contact through closed deals without a dedicated CRM administrator.$q$, $q$Small business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Independent professional managing client relationships$q$, $q$An insurance or real estate agent uses the CRM to log client interactions, tasks and follow-ups from a mobile device.$q$, $q$Independent agents and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Nonprofit tracking donor and contact relationships$q$, $q$A small nonprofit uses custom fields and pipelines to track donor relationships and outreach without complex setup.$q$, $q$Small nonprofits$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$Standard$q$, $q$$15/user/month$q$, $q$Monthly, cancel anytime$q$, NULL, $q$["Unlimited contacts and companies","25GB storage per user","Unlimited pipelines and custom fields","Task and calendar management","Mobile access","Free email and phone support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Less Annoying CRM was founded in 2009 by brothers Tyler King and Bracken King in St. Louis, Missouri, as a deliberately simple alternative to enterprise CRM platforms. The company has remained private, bootstrapped and profitable throughout its history, with roughly 25 employees today.$q$, $q$The product's defining philosophy is radical simplicity: a single pricing tier, no feature gating, and a focus on serving small businesses and independent professionals who want contact and pipeline tracking without the complexity of tools built for large enterprise sales organizations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes unified contact and company management, customizable sales pipelines, task and calendar management with reminders, lead tracking, custom fields, and user permission controls, all included at a single price with no feature restrictions.$q$, $q$The platform is a cloud-based web app hosted on AWS with mobile access, 25GB of storage per user, and lightweight integrations including Zapier, Google Calendar, Outlook and email logging, rather than a large native integration marketplace.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25b50035-747c-462e-a2db-a4e3b14e8c02', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Less Annoying CRM charges a single flat rate of $15 per user per month with no tiers, no contracts and no hidden fees. Every feature is included for every customer regardless of account size.$q$, $q$New users get a 30-day free trial with full feature access and no credit card required, allowing a complete evaluation of the product before committing to a paid plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$SEO automation and keyword research$q$, $q$Automated keyword and topic research paired with on-page SEO guidance for content production.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Internal linking suggestions$q$, $q$Recommends internal links between existing content to strengthen SEO authority.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Content refresh monitoring$q$, $q$Flags aging articles that are losing search rankings so teams know what to update.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$AI-assisted content repurposing$q$, $q$Turns webinars, podcasts and interviews into blog posts and LinkedIn content with video snippets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Content calendar and approvals$q$, $q$Plan, assign and approve content through a shared calendar and workflow.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$CMS integration$q$, $q$Publishes directly to content management systems including Webflow.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Sales enablement content packaging$q$, $q$Packages content for account executives to share directly with prospects.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Marketing insights$q$, $q$Ties content performance back to pipeline influence rather than only traffic metrics.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Unifies SEO, content calendar and distribution in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Content refresh monitoring helps maintain existing rankings, not just chase new content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$AI-assisted repurposing saves time turning long-form content into social posts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Ties content performance to pipeline and revenue rather than vanity metrics$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Sales enablement features connect marketing content directly to deal support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Pricing is not publicly transparent and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Reported pricing is relatively high for very small teams or solo founders$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Smaller ecosystem and community compared to larger, more established marketing platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Best suited to B2B SaaS motions, less relevant for B2C content marketing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$As a smaller startup, long-term roadmap and support scale is less proven than larger vendors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$What is Letterdrop used for$q$, $q$Letterdrop is used for B2B content marketing and SEO, helping teams plan, produce, optimize and distribute content across search, LinkedIn and sales channels.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Who founded Letterdrop$q$, $q$Letterdrop was founded by Parthi Loganathan, who serves as founder and CEO, and the company went through Y Combinator.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$How much does Letterdrop cost$q$, $q$Letterdrop does not publish official pricing; third-party sources report individual plans starting around $299/month and team plans around $1,249/month on annual billing, with custom enterprise pricing available.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Does Letterdrop help with SEO content refreshes$q$, $q$Yes, it includes content refresh monitoring that flags existing articles losing search rankings so teams can prioritize updates.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Does Letterdrop help repurpose content for LinkedIn$q$, $q$Yes, it includes AI-assisted tools to turn webinars, podcasts and interviews into LinkedIn posts and video snippets.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Is Letterdrop only for SEO$q$, $q$No, it also includes content calendar management, sales enablement content packaging, and distribution tools beyond just SEO.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Scaling organic content without adding headcount$q$, $q$A B2B SaaS marketing team uses Letterdrop's SEO automation and content refresh monitoring to grow organic traffic efficiently.$q$, $q$B2B SaaS marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Turning webinars into a content engine$q$, $q$A content marketer repurposes webinar recordings into blog posts and LinkedIn video snippets using Letterdrop's AI tools.$q$, $q$Individual content marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Supporting sales with content$q$, $q$An account executive uses Letterdrop-packaged content to share relevant material directly with prospects during deals.$q$, $q$Sales teams and account executives$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Individual$q$, $q$Reported around $299/month ($249/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Aimed at a single founder or account executive","SEO automation","Content calendar","AI-assisted repurposing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Team$q$, $q$Reported around $1,249/month$q$, $q$Annual billing$q$, NULL, $q$["Multi-user content team workflows","Approval workflows","Sales enablement content packaging","Marketing insights"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual, contact sales$q$, NULL, $q$["Custom seats and workflows","Dedicated support","Advanced integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Letterdrop is a Y Combinator-backed B2B content marketing and SEO platform founded by CEO Parthi Loganathan, headquartered in San Francisco. It was built to connect content planning, SEO execution and multi-channel distribution, including LinkedIn and sales enablement, into a single workflow rather than treating them as separate tools.$q$, $q$The platform targets B2B marketing teams and individual content creators who want their content output to directly influence pipeline and revenue, not just traffic or engagement metrics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Letterdrop includes SEO automation, keyword research, internal linking suggestions and content refresh monitoring to flag aging articles losing rankings. It also offers AI-assisted repurposing of long-form content like webinars and podcasts into LinkedIn posts and video snippets.$q$, $q$Additional functionality includes a content calendar with approval workflows, CMS integrations such as Webflow, sales enablement content packaging, and marketing insights that connect content performance to pipeline influence.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9edefa30-90ff-46ea-8aa7-f8de6be4c79c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Letterdrop does not publish full pricing on its own site and generally routes prospects through a custom quote process via demo requests. Third-party pricing trackers report an individual plan starting around $299/month (or roughly $249/month billed annually) and a team plan around $1,249/month on annual billing.$q$, $q$Enterprise pricing is available on request for larger organizations. Buyers should confirm current pricing directly with Letterdrop, since it is not officially published.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Grid-based availability input$q$, $q$Participants drag across a visual grid to mark when they are available, no account required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Availability heatmap$q$, $q$Overlays every participant's input to highlight the times with the most overlap.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$No sign-up required$q$, $q$Participants can respond via a shared link without creating an account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Google Calendar integration$q$, $q$Optionally checks a user's existing calendar events against the group availability grid.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Time zone support$q$, $q$Automatically handles time zone differences between participants.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Shareable event links$q$, $q$Organizers share a single link to collect availability from any group size.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Mobile-friendly interface$q$, $q$Works on mobile browsers for participants responding on the go.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Completely free$q$, $q$No paid tiers, subscriptions or account requirements at any point.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Completely free with no account required to participate$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Simple, fast way to find group availability without back-and-forth emails$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Cleaner, more modern interface than most free grid-scheduling alternatives$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Google Calendar integration helps avoid double-booking$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Works well for informal groups like clubs, classrooms and friend groups$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$No official company backing or transparency around ownership and funding$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$No dedicated customer support beyond informal, indie-level responsiveness$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Lacks advanced features like automated time-zone suggestions or calendar booking automation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Not designed for professional or enterprise scheduling needs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Long-term maintenance and uptime are less certain than a funded commercial product$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Is LettuceMeet free$q$, $q$Yes, LettuceMeet is completely free to use with no paid tiers or account requirements.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Do participants need to create an account to use LettuceMeet$q$, $q$No, participants can mark their availability directly through a shared link without signing up.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$How is LettuceMeet different from When2Meet$q$, $q$LettuceMeet offers a similar grid-based availability mechanic to When2Meet but with a more modern, mobile-friendly interface and optional Google Calendar integration.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Does LettuceMeet integrate with Google Calendar$q$, $q$Yes, it offers optional integration to check a user's existing calendar events against the group availability grid.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Who built LettuceMeet$q$, $q$LettuceMeet is understood to have started around 2018 as a small, independently built project rather than a venture-funded company.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Is LettuceMeet suitable for business scheduling$q$, $q$It is best suited for informal group scheduling like clubs, classrooms and friend groups rather than professional or enterprise scheduling needs.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Coordinating a student club meeting$q$, $q$A student organization uses LettuceMeet to find a common free time across many members without account sign-ups.$q$, $q$Student clubs and organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Planning a casual group event$q$, $q$A group of friends shares a LettuceMeet link to find a time that works for a get-together.$q$, $q$Informal friend and community groups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Scheduling a small team check-in$q$, $q$A small team without a shared calendar system uses LettuceMeet's grid to quickly find an overlapping meeting slot.$q$, $q$Small teams and volunteer groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited scheduling events","No account required for participants","Google Calendar integration","Time zone support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LettuceMeet is a free group scheduling tool that lets participants mark their availability on a shared visual grid, similar to the classic tool When2Meet, without requiring anyone to create an account. It dates to around 2018 and is understood to have started as a small independently built side project rather than a funded startup.$q$, $q$There is no publicly disclosed company structure, funding, or headquarters for LettuceMeet, and it operates as a free public utility with no pricing page, sales process or enterprise tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$An organizer creates an event with a date range and time window and shares a link; participants mark their availability directly on the grid without signing up, and LettuceMeet overlays everyone's input into a heatmap showing the best overlapping times.$q$, $q$The tool supports optional Google Calendar integration to check existing events against the group grid, and handles time zones automatically so participants in different regions can coordinate easily.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('636ed515-67d3-49ef-bcc8-c781f89295ef', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LettuceMeet is entirely free to use, with no paid tiers, subscriptions or account requirements for organizers or participants.$q$, $q$There is no enterprise or business pricing tier, consistent with its positioning as a free indie tool rather than a commercial SaaS product.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Real-time sales leaderboards$q$, $q$Live leaderboards that surface individual and team sales activity and rankings.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Sales gamification and contests$q$, $q$Contests, badges and public recognition tied to CRM-tracked sales behaviors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$KPI scorecards$q$, $q$Tracks individual and team key performance indicators against targets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Sales coaching workflows$q$, $q$Structured workflows for managers to review rep performance and deliver feedback.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Native Salesforce integration$q$, $q$Deep integration with Salesforce CRM to surface activity data in real time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Performance dashboards$q$, $q$Dashboards connecting specific sales behaviors to quota attainment.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$TV and office display mode$q$, $q$Leaderboards designed to be displayed on office screens for visibility.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Behavior-based motivation$q$, $q$Focuses on making CRM data entry and prospecting behaviors feel rewarding, not just tracked.$q$, 7);
