INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$No longer operates as a fully independent company, which may affect roadmap focus$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Gamification approach may not suit all sales team cultures$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Smaller footprint today compared to larger sales performance platforms like Gong or Clari$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$What is LevelEleven$q$, $q$LevelEleven is a sales gamification and performance management platform that uses leaderboards, KPI scorecards and coaching tools to motivate sales teams, typically layered on top of Salesforce.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Who owns LevelEleven now$q$, $q$LevelEleven was acquired in January 2022 and now operates as a product line within Ascent Cloud, alongside Ascent Cloud's Territory Planner and Geopointe products.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$How much does LevelEleven cost$q$, $q$LevelEleven does not publish pricing; it is quoted on a custom basis through Ascent Cloud's sales team based on user count and modules needed.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Does LevelEleven require Salesforce$q$, $q$LevelEleven is built around deep native Salesforce integration and is primarily used by organizations running Salesforce as their CRM.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$When was LevelEleven founded$q$, $q$LevelEleven launched as an independent company in October 2012, after starting as an internal tool called Contest Builder at ePrize in Detroit.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$What companies use LevelEleven$q$, $q$Publicly cited customers include Rogers Communications, 3M and Snap Finance, reported through Ascent Cloud's case studies.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Motivating a distributed sales team$q$, $q$A sales operations leader deploys real-time leaderboards to increase visibility and friendly competition across a distributed sales team.$q$, $q$Sales operations and enablement leaders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Coaching reps on specific behaviors$q$, $q$Sales managers use scorecards and coaching workflows to review rep performance against specific KPIs like call volume or pipeline updates.$q$, $q$Sales managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Driving CRM data hygiene$q$, $q$An organization uses gamified incentives to increase how consistently reps log activity and update opportunities in Salesforce.$q$, $q$Enterprise Salesforce-using sales teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$Custom$q$, $q$Custom pricing$q$, $q$Annual, contact sales$q$, NULL, $q$["Real-time leaderboards and gamification","KPI scorecards","Sales coaching workflows","Native Salesforce integration"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LevelEleven began as an internal tool called Contest Builder at Detroit-based ePrize, first shown at Dreamforce in September 2011, before spinning out as its own company under founder Bob Marsh in October 2012 with a $1 million seed round led by Detroit Venture Partners.$q$, $q$The company raised roughly $7.5 million in total funding before being acquired in January 2022 and folded into Ascent Cloud, a sales performance management company that also owns Territory Planner and Geopointe. LevelEleven continues to operate today as one of Ascent Cloud's core product lines.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LevelEleven layers gamification, including real-time leaderboards, contests and public recognition, directly on top of CRM activity such as Salesforce, making daily sales behaviors more visible and motivating for reps.$q$, $q$The platform also includes scorecards for tracking individual and team KPIs against targets, structured coaching workflows for managers, and dashboards that connect specific behaviors to quota attainment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('db13d6f8-fa65-4d11-8578-05ad62a17ca6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LevelEleven does not publish pricing publicly. Like most enterprise sales performance software, pricing is quoted on a custom basis depending on user count, which modules are needed, and the depth of Salesforce integration required.$q$, $q$Prospective buyers need to request a demo and custom quote directly from Ascent Cloud's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$ATS pipeline$q$, $q$Visual, customizable applicant tracking pipeline for managing candidates through the hiring process.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Talent CRM$q$, $q$Sourcing and nurturing tools for building relationships with passive candidates ahead of open roles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$AI-powered resume screening$q$, $q$AI-assisted screening and candidate matching against job requirements.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Unlimited interview transcription$q$, $q$Automatic transcription and note-taking for interviews at no additional volume limit.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Fraud and identity detection$q$, $q$Tools to flag candidate fraud and verify identity during the hiring process.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Customizable reporting$q$, $q$Analytics on hiring funnels, time-to-hire and diversity metrics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Career site and job distribution$q$, $q$Tools for building career pages and distributing job postings across boards.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Add-on modules$q$, $q$Optional Candidate Insights, VONQ AI screening, and onboarding workflow add-ons.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Combines ATS and CRM sourcing tools in a single platform$q$, 0);
