INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Can be more complex to configure than SMB-focused tools like JazzHR$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Competes closely with Greenhouse and Ashby, both frequently cited as comparable or preferred by some buyers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Long-term product direction is shaped by Employ's multi-brand portfolio strategy$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$What is Lever used for$q$, $q$Lever is used as an applicant tracking system and talent CRM, helping companies manage hiring pipelines and source and nurture passive candidates.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Who owns Lever now$q$, $q$Lever is owned by Employ Inc., which acquired it in August 2022 and also owns Jobvite and JazzHR.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$How much does Lever cost$q$, $q$Lever does not publish pricing publicly; it uses a custom quoting model based on company size, hiring volume and selected add-on modules.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Who founded Lever$q$, $q$Lever was founded in 2012 by Nate Smith, Sarah Nahm, Brian Noguchi and Randal Truong through Y Combinator.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$What is the difference between Lever, Jobvite and JazzHR$q$, $q$All three are ATS products owned by Employ Inc., generally positioned for different company sizes, with JazzHR for SMB, Jobvite for mid-market, and Lever for mid-market to enterprise.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Does Lever include a candidate CRM$q$, $q$Yes, Lever's core differentiation is combining a standard ATS pipeline with a talent CRM for sourcing and nurturing passive candidates.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Building a proactive sourcing pipeline$q$, $q$A talent acquisition team uses Lever's CRM to source and nurture passive candidates ahead of future openings.$q$, $q$Talent acquisition and recruiting teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Managing high-volume hiring at a growing company$q$, $q$A fast-growing technology company uses Lever's ATS pipeline to manage structured, high-volume hiring across departments.$q$, $q$Fast-growing technology companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Improving diversity and hiring funnel reporting$q$, $q$An HR leader uses Lever's customizable reporting to track diversity metrics and time-to-hire across the funnel.$q$, $q$HR and recruiting operations leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$Custom$q$, $q$Custom pricing$q$, $q$Annual, contact sales$q$, NULL, $q$["ATS and talent CRM","AI-powered resume screening","Unlimited interview transcription","Customizable reporting","Optional add-on modules"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lever is a talent acquisition suite combining an applicant tracking system and candidate relationship management CRM, founded in San Francisco in 2012 by Nate Smith, Sarah Nahm, Brian Noguchi and Randal Truong through Y Combinator.$q$, $q$In August 2022, Lever was acquired by Employ Inc., a recruiting software holding company backed by K1 Investment Management, joining Employ's portfolio alongside Jobvite and JazzHR. Together the combined company reported serving more than 18,000 customers at the time of the merger.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lever's core product combines a visual ATS pipeline with a talent CRM for sourcing and nurturing passive candidates, along with AI-powered resume screening, unlimited interview transcription, and fraud and identity-verification detection.$q$, $q$Additional capabilities include customizable hiring funnel and diversity reporting, career site and job distribution tools, and add-on modules for Candidate Insights, VONQ-powered AI screening, and onboarding workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e059a784-d8bc-45d5-ab94-fea4f0338c4e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lever does not publish pricing publicly and uses a fully custom quoting model that scales with company size, hiring volume and selected add-on modules, requested through a demo or quote form on Lever's site.$q$, $q$The company frames its pricing philosophy as paying only for the features a customer actually needs rather than a fixed bundle, differentiating it from flatter per-seat pricing used by some competitors.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$AI contract data extraction$q$, $q$Automatically extracts key terms, dates, obligations and clauses from uploaded or drafted contracts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Centralized contract repository$q$, $q$Single searchable repository for all company agreements with structured metadata.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$No-code workflow automation$q$, $q$Lets non-legal teams like sales or procurement route approval requests without manual legal involvement.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$AI Contract Assist$q$, $q$AI-assisted drafting and redlining support for contract creation and review.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Intake module$q$, $q$Structures how new contract requests enter the system from different departments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Renewal and obligation tracking$q$, $q$Surfaces upcoming renewals and contractual obligations automatically from extracted data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Business tool integrations$q$, $q$Integrates with email, Salesforce, HubSpot, Microsoft Word, Slack and Microsoft Teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Approval routing$q$, $q$Routes contract requests to the right reviewer based on configurable workflow rules.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Strong AI-based data extraction rooted in Allen Institute for AI research$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$No-code workflow automation reduces bottlenecks on legal teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Broad integrations with sales, procurement and communication tools already in use$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Now backed by DocuSign's infrastructure and Intelligent Agreement Management strategy$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Multiple G2 awards for usability and enterprise support prior to acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$No public pricing, requiring a sales conversation for cost estimates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Now being integrated into DocuSign, raising questions about long-term standalone product direction$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Smaller pre-acquisition scale compared to market leader Ironclad$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Best suited to organizations with meaningful contract volume, less relevant for very small teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Frequently confused with being an Ironclad acquisition rather than DocuSign, which can create research confusion$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$What is Lexion used for$q$, $q$Lexion is used for AI-powered contract and agreement management, including centralized contract storage, AI data extraction, and approval workflow automation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Who acquired Lexion$q$, $q$Lexion was acquired by DocuSign in May 2024 for approximately 165 million dollars, not by Ironclad as is sometimes assumed.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Who founded Lexion$q$, $q$Lexion was founded in Seattle in 2019 by Gaurav Oberoi, Emad Elwany and James Baird, with roots in the Allen Institute for Artificial Intelligence.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$How much does Lexion cost$q$, $q$Lexion does not publish pricing publicly; it is sold through a custom quote process based on company size and contract volume.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Does Lexion integrate with Salesforce and Slack$q$, $q$Yes, Lexion integrates with email, Salesforce, HubSpot, Microsoft Word, Slack and Microsoft Teams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Is Lexion still available as a standalone product$q$, $q$Lexion continues to operate its own branded product and website while being integrated into DocuSign's broader Intelligent Agreement Management strategy.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Automating contract approval routing$q$, $q$A sales operations team uses Lexion's no-code workflow to route contract approvals without waiting on manual legal review for every request.$q$, $q$Sales operations and procurement teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Centralizing scattered contracts$q$, $q$A legal team migrates contracts scattered across email and shared drives into Lexion's searchable, AI-tagged repository.$q$, $q$Corporate legal teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Tracking contract renewals and obligations$q$, $q$A finance or legal team uses Lexion's AI extraction to automatically track upcoming renewal dates and obligations across all vendor contracts.$q$, $q$Legal and finance operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$Custom$q$, $q$Custom pricing$q$, $q$Annual, contact sales$q$, NULL, $q$["AI contract data extraction","Centralized contract repository","No-code workflow automation","AI Contract Assist drafting support","Business tool integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lexion is an AI-powered contract and agreement management platform founded in Seattle in 2019 by Gaurav Oberoi, Emad Elwany and James Baird, with roots in the Allen Institute for Artificial Intelligence (AI2). It raised more than 35.2 million dollars in venture funding from investors including Madrona, Khosla Ventures, Citi Ventures and Point72 Ventures before being acquired.$q$, $q$Lexion was acquired by DocuSign, not Ironclad, in an all-cash deal announced in May 2024 valued at approximately 165 million dollars, as part of DocuSign's push into what it calls Intelligent Agreement Management.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Lexion combines a centralized contract repository with AI models that extract key terms, dates, obligations and clauses from agreements automatically, powering search, reporting and renewal tracking without manual tagging.$q$, $q$On top of the repository, Lexion offers no-code workflow automation for non-legal teams to route approval requests, an AI Contract Assist feature for drafting and redlining, and an Intake module, with integrations into email, Salesforce, HubSpot, Microsoft Word, Slack and Teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dcb87420-fbd7-430c-9df6-534d57e84b61', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lexion does not publish pricing publicly. Like most enterprise contract management platforms, it is sold through a custom quote process based on company size, contract volume and which modules a customer needs.$q$, $q$Prospective buyers are directed to contact sales through Lexion's site, which now also promotes its integration into DocuSign's broader product suite.$q$]::text[], 2);
