-- Enrichment marathon batch: Lemon Squeezy, Leonardo AI, Less Annoying CRM, Letterdrop, LettuceMeet, LevelEleven, Lever, Lexion

-- ── Lemon Squeezy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lemon Squeezy is a merchant-of-record platform that handles payments, subscriptions, tax and compliance for software sellers, now owned by Stripe.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based (transaction fees)$q$, pricing_model),
  starting_price = COALESCE($q$5% + $0.50 per transaction, no monthly fee$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Around 13 employees at the time of its 2024 acquisition; now operates as part of Stripe$q$, company_size),
  headquarters = COALESCE($q$Salt Lake City, Utah, USA (remote-first team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lemon Squeezy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lemon Squeezy review 2026: how the Stripe-owned merchant-of-record platform handles billing, tax and compliance for software sellers, plus pricing details.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lemon Squeezy is a merchant-of-record (MoR) commerce platform built specifically for software companies, indie developers and digital product creators who want to sell online without building their own billing, tax and compliance infrastructure. The company was founded by JR Farr, who serves as CEO, and launched its public product in 2021 after incorporating slightly earlier, positioning itself as an alternative to piecing together Stripe, a tax engine and a checkout UI from scratch. As a merchant of record, Lemon Squeezy legally becomes the seller on every transaction it processes, which means it takes on responsibility for calculating, collecting and remitting sales tax and VAT across the many jurisdictions a global software business might sell into, a task that is notoriously expensive and time-consuming for small teams to handle themselves. Lemon Squeezy remained a small, largely bootstrapped operation, reportedly staying at around 13 people even as it grew, and Farr has publicly discussed turning down a $50 million Series A term sheet in 2023 rather than raise venture capital. Instead, in July 2024 Stripe acquired Lemon Squeezy outright for an undisclosed sum, folding its merchant-of-record expertise into Stripe's own payments stack. Since the acquisition, Lemon Squeezy has continued to operate as a distinct product for existing and new customers, while Stripe has used the deal to accelerate its own native merchant-of-record offering, branded Stripe Managed Payments, with a stated migration path for Lemon Squeezy merchants over time. The core of the product is a hosted checkout and storefront system: sellers create products, pricing and license terms in a dashboard, then embed a Lemon Squeezy checkout overlay or link on their site, and Lemon Squeezy handles card processing, PayPal, subscription billing, dunning for failed payments, license key generation for software products, and an in-built affiliate program so sellers can recruit promoters without a separate affiliate tool. Fraud detection and chargeback handling are included, since Lemon Squeezy carries the liability as the merchant of record. Pricing is a single usage-based fee rather than tiered subscription plans: a base rate of 5% plus $0.50 per transaction, with no monthly platform fee, so sellers only pay when they make a sale. On top of the base rate, certain transaction types carry additional surcharges — international (non-US) transactions add 1.5%, PayPal payments add 1.5%, recurring subscription charges add 0.5%, abandoned cart recovery emails that convert add 5%, and affiliate-referred sales add 3%. Businesses selling at high volume or with very low-priced items (under roughly $10) can contact Lemon Squeezy's sales team for custom pricing, since the flat $0.50 fee disproportionately erodes margin on cheap products. The target audience is squarely indie hackers, solo SaaS founders, and small software and digital-product companies — people building plugins, templates, ebooks, developer tools, and subscription software who would otherwise need to register for sales tax in dozens of US states and EU countries. Lemon Squeezy competes most directly with Paddle and FastSpring, two older merchant-of-record platforms aimed at software companies, as well as with Gumroad for simpler digital-product sales and with building directly on Stripe (Stripe Billing plus a manual tax solution like Stripe Tax) for teams willing to own compliance themselves. Its differentiation has historically been a developer-friendly, modern UI, fast setup time, and pricing that undercuts enterprise-first MoR vendors, and post-acquisition it now also carries the trust and infrastructure reliability of being part of Stripe, even as its long-term product roadmap is expected to gradually merge into Stripe's own managed payments offering.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '38ebcc23-ac70-4e3b-9657-c3d8f9ce03db';

