-- ── Leonardo AI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Leonardo AI is an AI image and asset generation platform, originally built for game artists, now owned by Canva.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (token-based subscriptions)$q$, pricing_model),
  starting_price = COALESCE($q$Free (150 tokens/day); paid plans from $12/month$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$About 120 employees at the time of its 2024 acquisition, now larger within Canva$q$, company_size),
  headquarters = COALESCE($q$Sydney, New South Wales, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Leonardo AI Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Leonardo AI review 2026: how the Canva-owned AI image generator works, its token-based pricing tiers, key features, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Leonardo AI, styled Leonardo.Ai, is an AI-powered image and visual asset generation platform that began as a tool for video game developers before growing into a general-purpose creative image generator. It was founded in Sydney, Australia in December 2022 by a team that included JJ Fiasson, Chris Gillis and Jachin Bhasme, along with Peter Runham, Sami Ede and Ethan Smith, with the original mission of reducing the high cost and long production cycles of generating game art assets such as textures, character concepts and environment art. The product quickly expanded beyond gaming into general AI image generation for marketers, designers and hobbyists, built around fine-tuned and custom-trainable diffusion models, a real-time 'Canvas' editing mode, and features like the Consistent Character Engine for maintaining a recurring character's appearance across generations. Leonardo raised total funding of roughly $38.1 million across two rounds, including a Series A of about $30.1 million in 2023, backing rapid growth that took the platform past 19 million registered users within less than two years of launch. In July 2024, Canva announced it was acquiring Leonardo AI in an all-stock-and-cash deal reported by some outlets to be valued above $320 million, though the companies did not disclose official terms; all roughly 120 Leonardo employees, including its executive team, joined Canva, and Leonardo has continued to operate as a largely independent product and brand backed by Canva's resources, rather than being immediately folded into Canva's own interface. The architecture is built around Leonardo's own family of fine-tuned generative models alongside support for popular open models, plus tools for training custom LoRA (low-rank adaptation) models on a user's own reference images so brands or game studios can generate on-style assets repeatedly. Core features include text-to-image generation, image-to-image transformation, AI Canvas for inpainting and outpainting, a 3D texture generation tool aimed at game artists, real-time generation for rapid iteration, upscaling, and an API for developers to embed Leonardo's models into their own applications or pipelines. Pricing runs on a token-based freemium model with four tiers. The Free plan grants 150 tokens per day, enough for roughly 30 to 75 images depending on settings, but excludes private generations, the Consistent Character Engine, custom model training and API access. The Apprentice plan costs $12 per month and includes 8,500 tokens monthly plus private generations, the Consistent Character Engine and custom LoRA training. The Artisan plan, at $30 per month, raises the allotment to 25,000 tokens and unlocks the full creative suite including advanced Canvas editing, 3D texture generation and API access. The Maestro plan, at $60 per month, provides 60,000 tokens and is aimed at heavy commercial users who need maximum generation priority and custom model training at scale. Annual billing on any paid tier saves roughly 30% compared to monthly pricing. The target audience spans indie game developers and studios needing concept art and textures, marketers and content teams generating on-brand visuals at volume, and individual creators and hobbyists experimenting with AI art, with Canva's acquisition specifically aimed at giving Canva's much larger design-tool user base access to more sophisticated, fine-tunable image generation than Canva's native Magic Media tools previously offered. Leonardo AI's main competitors include Midjourney, the market leader for high-fidelity stylized image generation typically accessed through Discord; OpenAI's DALL-E and its integration into ChatGPT; Stability AI's Stable Diffusion and its various hosted front-ends; and Adobe Firefly, which is deeply embedded in Adobe's Creative Cloud suite. Leonardo differentiates itself through its roots in game-asset generation, its emphasis on fine-tunable custom models and consistent characters, and now through its backing by Canva, which gives it distribution to Canva's enterprise and Canva Pro customer base alongside continued operation as a standalone specialist tool for more advanced AI image workflows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '680a2bd4-9753-4f67-b86c-2cfe5c3b463e';

