-- ── Lever ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lever is a talent acquisition suite combining an applicant tracking system and CRM, now part of Employ Inc. alongside JazzHR and Jobvite.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (custom/enterprise pricing)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing, contact sales$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Around 225-300 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lever Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lever review 2026: features, pricing, and how this ATS and recruiting CRM fits into Employ Inc. alongside JazzHR and Jobvite, plus top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lever is a talent acquisition platform that combines an applicant tracking system (ATS) with a candidate relationship management (CRM) tool in a single product, a positioning it calls a Talent Acquisition Suite and one of the earlier examples of merging pipeline tracking with proactive candidate sourcing and nurturing. The company was founded in San Francisco in 2012 by Nate Smith, Sarah Nahm, Brian Noguchi and Randal Truong, and went through Y Combinator as part of its early development, growing over the following decade into one of the more widely adopted mid-market and enterprise recruiting platforms, headquartered at 1125 Mission Street in San Francisco. Lever raised venture funding across its independent life as a startup and built a customer base spanning fast-growing technology companies and larger enterprises that needed both structured hiring pipelines and long-term relationship-building with passive candidates, differentiating itself from older, more rigid ATS platforms by treating sourcing and nurturing as first-class, ongoing activities rather than something bolted onto a pipeline tool. On August 5, 2022, Employ Inc., a recruiting software holding company backed by private equity firm K1 Investment Management, announced its acquisition of Lever, bringing it together with Jobvite, a mid-market ATS Employ had acquired earlier, and JazzHR, a small and mid-sized business-focused ATS that Jobvite itself had acquired in 2021 alongside the recruitment process outsourcing firm NXTThing RPO. This combination made Employ one of the largest recruiting software portfolios in the industry, with the company stating that together its brands served more than 18,000 customers, operated a network of over 1,200 partners, and hosted roughly 3.1 million open jobs and 500 million candidate records across its combined platforms at the time of the merger. Since the acquisition, Lever has continued to operate under its own brand and product within the Employ portfolio, generally positioned toward the higher end of Employ's customer base (with JazzHR serving smaller SMB customers and Jobvite serving the mid-market), rather than being immediately merged into a single unified product. Architecturally, Lever functions as a cloud-based SaaS platform centered on a visual, pipeline-based hiring workflow, and its core features include the ATS pipeline itself, a talent CRM for sourcing and nurturing passive candidates over time, AI-powered resume screening and candidate matching, interview scheduling and unlimited interview transcription and note-taking tools, fraud and identity-verification detection for candidates, customizable reporting and analytics on hiring funnels and diversity metrics, and career site and job posting distribution tools. Add-on modules available on top of the core platform include Candidate Insights, AI screening delivered through a partnership with VONQ, and onboarding workflow tools that hand off a hired candidate into a company's HR systems. Lever does not publish pricing publicly; instead it uses a fully custom quoting model explicitly framed around the idea that customers should "pay for what you need to hire, not complexity you'll never use," meaning pricing scales with company size, hiring volume, and which add-on modules a customer selects, available only by requesting a custom quote or demo through Lever's sales team. The target audience is mid-market to enterprise companies, particularly fast-growing technology and venture-backed companies, that need both a structured applicant pipeline and a proactive sourcing and relationship-building tool for building talent pools ahead of need, rather than only reacting to inbound applications. Lever's competitors include Greenhouse, its most frequently cited direct rival and the other major independent ATS aimed at similar company sizes, as well as Ashby, a newer entrant popular with venture-backed startups, Workday Recruiting and SmartRecruiters at the larger enterprise end, and its own sibling products JazzHR and Jobvite within the Employ portfolio, which now effectively compete for different segments of the same market under one parent company. Lever differentiates itself through its combined ATS-plus-CRM architecture, unlimited interview transcription, and its continued strong reputation among talent acquisition teams for pipeline visibility and sourcing workflows, even as its long-term product strategy is now shaped by Employ's broader multi-brand portfolio strategy rather than operating as a fully independent company.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e059a784-d8bc-45d5-ab94-fea4f0338c4e';

