-- ── Lexion ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Lexion is an AI-powered contract and agreement management platform, acquired by DocuSign in 2024 to power its intelligent agreement management push.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (custom/enterprise pricing)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing, contact sales$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small (now integrated within DocuSign)$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Lexion Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Lexion review 2026: how this AI contract management platform works, its 2024 acquisition by DocuSign, key features, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Lexion is an AI-powered contract and agreement management platform built to help legal, sales, procurement, HR and finance teams centralize contracts, automate routine review tasks, and manage approval workflows without requiring heavy involvement from IT or legal operations staff for every request. It's worth correcting a common point of confusion here: Lexion was acquired by DocuSign in 2024, not by Ironclad as is sometimes assumed given that Ironclad is a well-known competitor in the same contract lifecycle management space; DocuSign announced the all-cash acquisition in May 2024 for approximately 165 million dollars, describing it as a step toward building out its own Intelligent Agreement Management category. The company was founded in Seattle in 2019 by Gaurav Oberoi, Emad Elwany and James Baird, who built the product out of research and technology connections to the Allen Institute for Artificial Intelligence (AI2), giving Lexion an early foundation in applied natural language processing for extracting and structuring information from contract documents. Prior to its acquisition, Lexion raised more than 35.2 million dollars in venture funding from investors including Madrona Venture Group, Khosla Ventures, Citi Ventures and Point72 Ventures, along with an unusual strategic investor in the law firm Wilson Sonsini Goodrich & Rosati, reflecting Lexion's positioning squarely within legal-tech and its close relationships with corporate legal departments. The core architecture of Lexion combines a centralized contract repository with AI models trained to read and extract key terms, dates, obligations and clauses from uploaded or newly drafted agreements, surfacing that structured data for search, reporting and renewal tracking without requiring manual tagging. On top of that repository, Lexion built a no-code workflow and automation layer, marketed as Lexion Workflow, that lets non-legal teams like sales or procurement kick off approval requests, route them to the right reviewer, and track status without needing a lawyer to manually manage every step, alongside an AI Contract Assist feature for drafting assistance and redlining support, and an Intake module for structuring how new contract requests enter the system. Lexion integrates with common business tools including email, Salesforce, HubSpot, Microsoft Word, Slack and Microsoft Teams, letting contract workflows plug into the systems sales, procurement and other departments already use daily rather than forcing them into a standalone legal tool. Since being acquired, Lexion's technology and team have been folded into DocuSign's broader Intelligent Agreement Management strategy, joining DocuSign's existing eSignature and contract lifecycle management capabilities, with Lexion's own branded website continuing to operate and highlight the "Lexion joins forces with Docusign" transition for existing customers and prospects. Pricing for Lexion has never been publicly listed on its website; like most enterprise contract management software, it is sold through a custom quote process based on company size, contract volume and which modules (repository, workflow automation, AI drafting assistance) a customer needs, and prospective buyers are directed to contact sales rather than see published tiers. The target audience is primarily mid-market and enterprise legal, procurement and sales operations teams, particularly organizations with a high volume of recurring vendor, sales and partnership contracts who want faster turnaround on approvals without expanding legal headcount. Lexion's competitors in the contract lifecycle management and AI contract review space include Ironclad, a frequently confused-for competitor and market leader with strong sales-facing contracting workflows; DocuSign's own pre-acquisition CLM product; ContractPodAi; Icertis, which is positioned more toward large enterprise; Juro; and Spellbook, which focuses more narrowly on AI-assisted contract drafting inside Word. Lexion differentiated itself pre-acquisition through its AI2 research roots and strength in AI-based data extraction from existing contracts, and its acquisition by DocuSign is generally read as DocuSign's move to compete more directly with Ironclad and other CLM-first vendors by adding deep AI contract understanding on top of its existing signature and agreement infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'dcb87420-fbd7-430c-9df6-534d57e84b61';

